+}
+
+interface Invoice {
+  id: number;
+  invoiceNo: string;
+  orderId: number | null;
+  issuedAt: string;
+  buyerName: string | null;
+  qualifiedInvoiceFlag: boolean;
+  taxRateSummary: string | null;
