+}
+
+export interface CreateOrderInput {
+  orderNo: string;
+  customerId?: number | null;
+  orderedAt: string;
+  channel: string;
+  subtotalTaxIncluded: number;
+  taxAmount?: number | null;
+  paymentStatus?: PaymentStatus;
+  deliveryStatus?: DeliveryStatus;
+  refundStatus?: RefundStatus;
