+import { describe, expect, it } from 'vitest';
+import { bootstrap, type DB } from '../src/db/bootstrap.js';
+import {
+  createOrder,
+  deleteOrder,
+  exportOrdersCsv,
+  getOrder,
+  importOrdersCsv,
+  listOrders,
+  monthlySummary,
+  updateDeliveryStatus,
+  updateOrder,
+  updatePaymentStatus,
+  updateRefundStatus,
+} from '../src/services/sales.js';
+
+describe('sales service', () => {
+  it('注文CRUDとステータス更新で監査ログを記録する', () => {
+    const db = bootstrap({ filename: ':memory:' });
+    const productId = seedProduct(db);
+
+    const created = createOrder(db, {
+      orderNo: 'ORD-001',
+      orderedAt: '2026-06-09',
+      channel: 'direct',
+      subtotalTaxIncluded: 11_000,
+      taxAmount: 1_000,
+      items: [{ productId, quantity: 2, unitPriceTaxIncluded: 5_500 }],
+      invoice: {
+        invoiceNo: 'INV-001',
+        issuedAt: '2026-06-10',
+        buyerName: '合同会社サンプル',
+        qualifiedInvoiceFlag: true,
+        taxRateSummary: '{"10":1000}',
+      },
+    });
+
+    expect(created).toMatchObject({
+      id: expect.any(Number),
+      orderNo: 'ORD-001',
+      paymentStatus: 'pending',
+      deliveryStatus: 'not_delivered',
+      refundStatus: 'none',
+      subtotalTaxIncluded: 11_000,
+      taxAmount: 1_000,
+    });
+    expect(created.items).toHaveLength(1);
+    expect(created.invoice).toMatchObject({ invoiceNo: 'INV-001', qualifiedInvoiceFlag: true });
+
+    const updated = updateOrder(db, created.id, { channel: 'booth', subtotalTaxIncluded: 12_100, taxAmount: 1_100 });
+    expect(updated).toMatchObject({ channel: 'booth', subtotalTaxIncluded: 12_100, taxAmount: 1_100 });
+
+    expect(updatePaymentStatus(db, created.id, 'paid')?.paymentStatus).toBe('paid');
+    expect(updateDeliveryStatus(db, created.id, 'delivered')?.deliveryStatus).toBe('delivered');
+    expect(updateRefundStatus(db, created.id, 'refunded')?.refundStatus).toBe('refunded');
+
+    expect(deleteOrder(db, created.id)).toBe(true);
+    expect(getOrder(db, created.id)).toBeNull();
+
+    const auditActions = db
+      .prepare('SELECT action FROM audit_logs WHERE entity_type = ? ORDER BY id ASC')
+      .all('order')
+      .map((row) => (row as { action: string }).action);
+    expect(auditActions).toEqual(['create', 'update', 'update', 'update', 'update', 'delete']);
+    db.close();
+  });
+
+  it('CSV export/import の往復で注文・明細・請求書データを保持する', () => {
+    const sourceDb = bootstrap({ filename: ':memory:' });
+    const sourceProductId = seedProduct(sourceDb);
+    createOrder(sourceDb, {
+      orderNo: 'ORD-CSV-001',
+      orderedAt: '2026-06-15',
+      channel: 'store',
+      subtotalTaxIncluded: 22_000,
+      taxAmount: 2_000,
+      paymentStatus: 'paid',
+      deliveryStatus: 'delivered',
+      refundStatus: 'none',
+      items: [{ productId: sourceProductId, quantity: 1, unitPriceTaxIncluded: 22_000 }],
+      invoice: {
+        invoiceNo: 'INV-CSV-001',
+        issuedAt: '2026-06-16',
+        buyerName: '株式会社CSV',
+        qualifiedInvoiceFlag: true,
+        taxRateSummary: '{"10":2000}',
+      },
+    });
+
+    const csv = exportOrdersCsv(sourceDb);
+    const targetDb = bootstrap({ filename: ':memory:' });
+    seedProduct(targetDb, sourceProductId);
+    const result = importOrdersCsv(targetDb, csv);
+    const imported = listOrders(targetDb);
+
+    expect(result).toEqual({ imported: 1, created: 1, updated: 0 });
+    expect(imported).toHaveLength(1);
+    expect(imported[0]).toMatchObject({
+      orderNo: 'ORD-CSV-001',
+      orderedAt: '2026-06-15',
+      channel: 'store',
+      subtotalTaxIncluded: 22_000,
+      taxAmount: 2_000,
+      paymentStatus: 'paid',
+      deliveryStatus: 'delivered',
+    });
+    expect(imported[0]?.items[0]).toMatchObject({ productId: sourceProductId, quantity: 1, unitPriceTaxIncluded: 22_000 });
+    expect(imported[0]?.invoice).toMatchObject({ invoiceNo: 'INV-CSV-001', buyerName: '株式会社CSV' });
+    sourceDb.close();
+    targetDb.close();
+  });
+
+  it('monthlySummary は年月別に整数金額を集計する', () => {
+    const db = bootstrap({ filename: ':memory:' });
+    createOrder(db, {
+      orderNo: 'ORD-SUM-001',
+      orderedAt: '2026-06-01',
+      channel: 'direct',
+      subtotalTaxIncluded: 11_000,
+      taxAmount: 1_000,
+      paymentStatus: 'paid',
+      refundStatus: 'none',
+    });
+    createOrder(db, {
+      orderNo: 'ORD-SUM-002',
+      orderedAt: '2026-06-30',
+      channel: 'direct',
+      subtotalTaxIncluded: 5_500,
+      taxAmount: 500,
+      paymentStatus: 'pending',
+      refundStatus: 'refunded',
+    });
+    createOrder(db, {
+      orderNo: 'ORD-SUM-003',
+      orderedAt: '2026-07-01',
+      channel: 'direct',
+      subtotalTaxIncluded: 3_300,
+      taxAmount: 300,
+      paymentStatus: 'pending',
+    });
+
+    expect(monthlySummary(db)).toEqual([
+      {
+        month: '2026-06',
+        salesTaxIncluded: 16_500,
+        taxAmount: 1_500,
+        uncollectedAmount: 5_500,
+        refundAmount: 5_500,
+        orderCount: 2,
+      },
+      {
+        month: '2026-07',
+        salesTaxIncluded: 3_300,
+        taxAmount: 300,
+        uncollectedAmount: 3_300,
+        refundAmount: 0,
+        orderCount: 1,
+      },
+    ]);
+    expect(monthlySummary(db, '2026-06')).toHaveLength(1);
+    db.close();
+  });
+});
+
+function seedProduct(db: DB, id?: number): number {
+  const params = {
+    id: id ?? null,
+    sku: `SKU-${id ?? 'AUTO'}`,
+    title: 'テスト商品',
+    productType: 'download',
+    priceTaxIncluded: 11_000,
+  };
+  const result = db
+    .prepare(
+      `INSERT INTO products (id, sku, title, product_type, price_tax_included)
+       VALUES (@id, @sku, @title, @productType, @priceTaxIncluded)`,
+    )
+    .run(params);
+  return id ?? Number(result.lastInsertRowid);
+}
diff --git a/packages/server/src/routes/sales.ts b/packages/server/src/routes/sales.ts
new file mode 100755
index 0000000000000000000000000000000000000000..0a139a6a0088ff966bb0734eecdd85dd12d4b43a
--- /dev/null
+++ b/packages/server/src/routes/sales.ts
@@ -0,0 +1,655 @@
+import type { FastifyInstance } from 'fastify';
+import { parseCsv, serializeCsv, writeAudit, yearMonth, type CsvRow, type DB } from '@free-worker/core';
+
+interface Order {
+  id: number;
+  orderNo: string;
+  customerId: number | null;
+  orderedAt: string;
+  channel: string;
+  subtotalTaxIncluded: number;
+  taxAmount: number | null;
+  paymentStatus: string;
+  deliveryStatus: string;
+  refundStatus: string;
+  items: OrderItem[];
+  invoice: Invoice | null;
+}
+
+interface OrderItem {
+  id: number;
+  orderId: number;
+  productId: number;
+  quantity: number;
+  unitPriceTaxIncluded: number;
+}
+
+interface Invoice {
+  id: number;
+  invoiceNo: string;
+  orderId: number | null;
+  issuedAt: string;
+  buyerName: string | null;
+  qualifiedInvoiceFlag: boolean;
+  taxRateSummary: string | null;
+  attachmentId: number | null;
+}
+
+interface OrderPayload {
+  orderNo?: unknown;
+  customerId?: unknown;
+  orderedAt?: unknown;
+  channel?: unknown;
+  subtotalTaxIncluded?: unknown;
+  taxAmount?: unknown;
+  paymentStatus?: unknown;
+  deliveryStatus?: unknown;
+  refundStatus?: unknown;
+  items?: unknown;
+  invoice?: unknown;
+}
+
+interface OrderItemPayload {
+  productId?: unknown;
+  quantity?: unknown;
+  unitPriceTaxIncluded?: unknown;
+}
+
+interface InvoicePayload {
+  invoiceNo?: unknown;
+  issuedAt?: unknown;
+  buyerName?: unknown;
+  qualifiedInvoiceFlag?: unknown;
+  taxRateSummary?: unknown;
+  attachmentId?: unknown;
+}
+
+interface OrderRow {
+  id: number;
+  order_no: string;
+  customer_id: number | null;
+  ordered_at: string;
+  channel: string;
+  subtotal_tax_included: number;
+  tax_amount: number | null;
+  payment_status: string;
+  delivery_status: string;
+  refund_status: string;
+}
+
+interface OrderItemRow {
+  id: number;
+  order_id: number;
+  product_id: number;
+  quantity: number;
+  unit_price_tax_included: number;
+}
+
+interface InvoiceRow {
+  id: number;
+  invoice_no: string;
+  order_id: number | null;
+  issued_at: string;
+  buyer_name: string | null;
+  qualified_invoice_flag: number;
+  tax_rate_summary: string | null;
+  attachment_id: number | null;
+}
+
+interface IdParams {
+  id: string;
+}
+
+interface SummaryQuery {
+  month?: string;
+}
+
+const CSV_COLUMNS = [
+  'orderNo',
+  'customerId',
+  'orderedAt',
+  'channel',
+  'subtotalTaxIncluded',
+  'taxAmount',
+  'paymentStatus',
+  'deliveryStatus',
+  'refundStatus',
+  'itemsJson',
+  'invoiceNo',
+  'invoiceIssuedAt',
+  'buyerName',
+  'qualifiedInvoiceFlag',
+  'taxRateSummary',
+  'attachmentId',
+];
+
+export async function salesRoutes(app: FastifyInstance): Promise<void> {
+  app.get('/api/sales', async () => listOrders(app.db));
+
+  app.get<{ Querystring: SummaryQuery }>('/api/sales/summary', async (req) => monthlySummary(app.db, req.query.month));
+
+  app.get('/api/sales/export', async (_req, reply) => {
+    reply.header('content-type', 'text/csv; charset=utf-8');
+    return exportOrdersCsv(app.db);
+  });
+
+  app.post<{ Body: { csv?: unknown } }>('/api/sales/import', async (req, reply) => {
+    if (typeof req.body?.csv !== 'string') {
+      reply.code(400);
+      return { error: 'csv_required' };
+    }
+    try {
+      return importOrdersCsv(app.db, req.body.csv);
+    } catch (error) {
+      reply.code(400);
+      return { error: 'invalid_csv', message: error instanceof Error ? error.message : 'invalid csv' };
+    }
+  });
+
+  app.get<{ Params: IdParams }>('/api/sales/:id', async (req, reply) => {
+    const id = parseId(req.params.id);
+    if (id == null) {
+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    const order = getOrder(app.db, id);
+    if (!order) {
+      reply.code(404);
+      return { error: 'not_found' };
+    }
+    return order;
+  });
+
+  app.post<{ Body: OrderPayload }>('/api/sales', async (req, reply) => {
+    try {
+      const created = createOrder(app.db, req.body ?? {});
+      reply.code(201);
+      return created;
+    } catch (error) {
+      reply.code(400);
+      return { error: 'invalid_payload', message: error instanceof Error ? error.message : 'invalid payload' };
+    }
+  });
+
+  app.put<{ Body: OrderPayload; Params: IdParams }>('/api/sales/:id', async (req, reply) => {
+    const id = parseId(req.params.id);
+    if (id == null) {
+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    if (!getOrder(app.db, id)) {
+      reply.code(404);
+      return { error: 'not_found' };
+    }
+    try {
+      return updateOrder(app.db, id, req.body ?? {});
+    } catch (error) {
+      reply.code(400);
+      return { error: 'invalid_payload', message: error instanceof Error ? error.message : 'invalid payload' };
+    }
+  });
+
+  app.patch<{ Body: { status?: unknown }; Params: IdParams }>('/api/sales/:id/payment', async (req, reply) => {
+    return updateStatus(app, req.params.id, req.body?.status, 'paymentStatus', reply);
+  });
+
+  app.patch<{ Body: { status?: unknown }; Params: IdParams }>('/api/sales/:id/refund', async (req, reply) => {
+    return updateStatus(app, req.params.id, req.body?.status, 'refundStatus', reply);
+  });
+
+  app.patch<{ Body: { status?: unknown }; Params: IdParams }>('/api/sales/:id/delivery', async (req, reply) => {
+    return updateStatus(app, req.params.id, req.body?.status, 'deliveryStatus', reply);
+  });
+
+  app.delete<{ Params: IdParams }>('/api/sales/:id', async (req, reply) => {
+    const id = parseId(req.params.id);
+    if (id == null) {
+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    const before = getOrder(app.db, id);
+    if (!before) {
+      reply.code(404);
+      return { error: 'not_found' };
+    }
+    app.db.transaction(() => {
+      writeAudit(app.db, { action: 'delete', entityType: 'order', entityId: id, before });
+      app.db.prepare('DELETE FROM orders WHERE id = ?').run(id);
+    })();
+    reply.code(204);
+    return undefined;
+  });
+}
+
+function createOrder(db: DB, body: OrderPayload): Order {
+  const payload = normalizeCreate(body);
+  return db.transaction(() => {
+    const result = db
+      .prepare(
+        `INSERT INTO orders
+          (order_no, customer_id, ordered_at, channel, subtotal_tax_included, tax_amount,
+           payment_status, delivery_status, refund_status)
+         VALUES
+          (@orderNo, @customerId, @orderedAt, @channel, @subtotalTaxIncluded, @taxAmount,
+           @paymentStatus, @deliveryStatus, @refundStatus)`,
+      )
+      .run(payload);
+    const orderId = Number(result.lastInsertRowid);
+    replaceItems(db, orderId, payload.items);
+    replaceInvoice(db, orderId, payload.invoice);
+    const created = getOrderOrThrow(db, orderId);
+    writeAudit(db, { action: 'create', entityType: 'order', entityId: orderId, after: created });
+    return created;
+  })();
+}
+
+function updateOrder(db: DB, id: number, body: OrderPayload): Order {
+  const before = getOrderOrThrow(db, id);
+  const payload = normalizePatch(body);
+  return db.transaction(() => {
+    db.prepare(
+      `UPDATE orders
+       SET order_no = CASE WHEN @hasOrderNo = 1 THEN @orderNo ELSE order_no END,
+           customer_id = CASE WHEN @hasCustomerId = 1 THEN @customerId ELSE customer_id END,
+           ordered_at = CASE WHEN @hasOrderedAt = 1 THEN @orderedAt ELSE ordered_at END,
+           channel = CASE WHEN @hasChannel = 1 THEN @channel ELSE channel END,
+           subtotal_tax_included = CASE
+             WHEN @hasSubtotalTaxIncluded = 1 THEN @subtotalTaxIncluded
+             ELSE subtotal_tax_included
+           END,
+           tax_amount = CASE WHEN @hasTaxAmount = 1 THEN @taxAmount ELSE tax_amount END,
+           payment_status = CASE WHEN @hasPaymentStatus = 1 THEN @paymentStatus ELSE payment_status END,
+           delivery_status = CASE WHEN @hasDeliveryStatus = 1 THEN @deliveryStatus ELSE delivery_status END,
+           refund_status = CASE WHEN @hasRefundStatus = 1 THEN @refundStatus ELSE refund_status END
+       WHERE id = @id`,
+    ).run({ id, ...payload.order });
+    if (payload.hasItems) replaceItems(db, id, payload.items);
+    if (payload.hasInvoice) replaceInvoice(db, id, payload.invoice);
+    const after = getOrderOrThrow(db, id);
+    writeAudit(db, { action: 'update', entityType: 'order', entityId: id, before, after });
+    return after;
+  })();
+}
+
+function updateStatus(
+  app: FastifyInstance,
+  idText: string,
+  statusValue: unknown,
+  field: 'paymentStatus' | 'refundStatus' | 'deliveryStatus',
+  reply: { code: (statusCode: number) => unknown },
+): Order | { error: string; message?: string } {
+  const id = parseId(idText);
+  if (id == null) {
+    reply.code(400);
+    return { error: 'invalid_id' };
+  }
+  if (!getOrder(app.db, id)) {
+    reply.code(404);
+    return { error: 'not_found' };
+  }
+  try {
+    return updateOrder(app.db, id, { [field]: parseRequiredString(statusValue, 'status') });
+  } catch (error) {
+    reply.code(400);
+    return { error: 'invalid_payload', message: error instanceof Error ? error.message : 'invalid payload' };
+  }
+}
+
+function listOrders(db: DB): Order[] {
+  const rows = db.prepare('SELECT * FROM orders ORDER BY ordered_at ASC, id ASC').all() as OrderRow[];
+  return rows.map((row) => mapOrder(db, row));
+}
+
+function getOrder(db: DB, id: number): Order | null {
+  const row = db.prepare('SELECT * FROM orders WHERE id = ?').get(id) as OrderRow | undefined;
+  return row ? mapOrder(db, row) : null;
+}
+
+function getOrderOrThrow(db: DB, id: number): Order {
+  const order = getOrder(db, id);
+  if (!order) throw new Error(`order not found: ${id}`);
+  return order;
+}
+
+function getOrderByNo(db: DB, orderNo: string): Order | null {
+  const row = db.prepare('SELECT * FROM orders WHERE order_no = ?').get(orderNo) as OrderRow | undefined;
+  return row ? mapOrder(db, row) : null;
+}
+
+function normalizeCreate(body: OrderPayload): {
+  orderNo: string;
+  customerId: number | null;
+  orderedAt: string;
+  channel: string;
+  subtotalTaxIncluded: number;
+  taxAmount: number | null;
+  paymentStatus: string;
+  deliveryStatus: string;
+  refundStatus: string;
+  items: OrderItemPayload[];
+  invoice: InvoicePayload | null;
+} {
+  return {
+    orderNo: parseRequiredString(body.orderNo, 'orderNo'),
+    customerId: parseNullableInteger(body.customerId, 'customerId'),
+    orderedAt: parseRequiredString(body.orderedAt, 'orderedAt'),
+    channel: parseRequiredString(body.channel, 'channel'),
+    subtotalTaxIncluded: parseRequiredInteger(body.subtotalTaxIncluded, 'subtotalTaxIncluded'),
+    taxAmount: parseNullableInteger(body.taxAmount, 'taxAmount'),
+    paymentStatus: parseOptionalString(body.paymentStatus, 'paymentStatus') ?? 'pending',
+    deliveryStatus: parseOptionalString(body.deliveryStatus, 'deliveryStatus') ?? 'not_delivered',
+    refundStatus: parseOptionalString(body.refundStatus, 'refundStatus') ?? 'none',
+    items: parseItems(body.items),
+    invoice: parseInvoice(body.invoice),
+  };
+}
+
+function normalizePatch(body: OrderPayload): {
+  order: Record<string, string | number | null>;
+  hasItems: boolean;
+  items: OrderItemPayload[];
+  hasInvoice: boolean;
+  invoice: InvoicePayload | null;
+} {
+  const order: Record<string, string | number | null> = {
+    hasOrderNo: 0,
+    orderNo: null,
+    hasCustomerId: 0,
+    customerId: null,
+    hasOrderedAt: 0,
+    orderedAt: null,
+    hasChannel: 0,
+    channel: null,
+    hasSubtotalTaxIncluded: 0,
+    subtotalTaxIncluded: null,
+    hasTaxAmount: 0,
+    taxAmount: null,
+    hasPaymentStatus: 0,
