+      items: [{ productId: sourceProductId, quantity: 1, unitPriceTaxIncluded: 22_000 }],
+      invoice: {
+        invoiceNo: 'INV-CSV-001',
+        issuedAt: '2026-06-16',
+        buyerName: '株式会社CSV',
+        qualifiedInvoiceFlag: true,
+        taxRateSummary: '{"10":2000}',
+      },
